settings.custom_css:
selector .content {
    color: #ffffff;
    font-size: 18px;
    font-weight: 600;
    margin-top: 16px;
}
@media (max-width: 767px) {
    selector .content {
    font-size: 16px;
    }
}

selector {
    mask-image: linear-gradient(90deg, transparent 0, #000 15%, #000 85%, transparent 100%);
    -webkit-mask-image: linear-gradient(90deg, transparent 0, #000 15%, #000 85%, transparent 100%);
}
selector img {
    mix-blend-mode: multiply;
}

selector .suessco-apps {
  --suessco-apps-sticky-top: 120px;
  width: 100%;
  padding: 0;
  background: #ffffff;
  overflow: visible;
}
selector .suessco-apps__inner {
  width: 100%;
  max-width: 1392px;
  margin: 0 auto;
}
selector .suessco-apps__head {
  max-width: 1000px;
  margin: 0 auto 48px;
  text-align: center;
}
selector .suessco-apps__heading {
  margin: 0 0 24px;
}
selector .suessco-apps__subtitle {
  font-size: 18px;
}
selector .suessco-apps__stage {
  display: grid;
  grid-template-columns: minmax(0, 1fr) 100px;
  gap: 32px;
  align-items: start;
  overflow: visible;
}
selector .suessco-apps__cards {
  display: flex;
  flex-direction: column;
  gap: 32px;
  overflow: visible;
}

selector .suessco-apps__card {
  position: sticky;
  top: var(--suessco-apps-sticky-top);
  z-index: var(--card-index);
  width: 100%;
  min-height: 480px;
  display: grid;
  grid-template-columns: minmax(0, 1fr) 50%;
  align-items: center;
  gap: 40px;

  padding: 9px 8px 8px 48px;

  background: #f7f7f8;
  border-radius: 40px;
  overflow: hidden;

  transform: translateY(var(--card-y, 0px)) scale(var(--card-scale, 1));
  transform-origin: center top;
  opacity: var(--card-opacity, 1);

  transition:
    transform 0.45s cubic-bezier(0.22, 1, 0.36, 1),
    opacity 0.45s cubic-bezier(0.22, 1, 0.36, 1),
    box-shadow 0.45s cubic-bezier(0.22, 1, 0.36, 1);

  will-change: transform, opacity;
}

.suessco-apps__card.is-active {
  box-shadow: 0 24px 70px rgba(20, 35, 75, 0.08);
}

.suessco-apps__card-content {
  width: 100%;
  max-width: 420px;
}

.suessco-apps__card-title {
  margin: 0 0 20px;
  font-size: 36px;
  line-height: 1.2;
  font-weight: 500;
  letter-spacing: -0.02em;
  color: #14234b;
}

.suessco-apps__card-description {
  font-size: 18px;
  line-height: 1.5;
  font-weight: 400;
  letter-spacing: -0.02em;
  color: #14234b;
  margin-bottom: 32px;
}

.suessco-apps__card-description p { margin: 0; }

/*btn (outline) */
.suessco-apps__card-btn {
  display: inline-flex;
  align-items: center;
  gap: 8px;
    background-color: #FFFFFF00;
    fill: var( --e-global-color-accent );
    color: var( --e-global-color-accent );
    border-radius: 50px;
    border-style: solid;
    border-width: 1px 1px 1px 1px;
    border-color: var( --e-global-color-accent );
    padding: 18px 33px 18px 33px;
  transition: background 0.3s, color 0.3s;
}

/* btn — hover(filled) */
selector .suessco-apps__card-btn:hover {
    background-color: var( --e-global-color-accent );
    color: #FFFFFF;
    box-shadow: 
		0px 4px 10px 0px #1476FF52,
		2px 2px 4px 0px #FFFFFF40 inset;
}
selector .suessco-apps__card-btn svg {
  flex-shrink: 0;
  transition: transform 0.25s;
}
selector .suessco-apps__card-btn:hover svg {
  transform: translateX(3px);
}
selector .suessco-apps__image-wrap {
  width: 100%;
  height: 464px;
  border-radius: 32px;
  overflow: hidden;
}
selector .suessco-apps__image {
  width: 100%;
  height: 100%;
  display: block;
  object-fit: cover;
}
/* Counter */
selector .suessco-apps__counter {
  position: sticky;
  top: var(--suessco-apps-sticky-top);
  width: 100px;
  height: 480px;
  display: flex;
  flex-direction: column;
  align-items: center;
  justify-content: center;
  padding-top: 12px;
}
selector .suessco-apps__counter-current {
  width: 100%;
  height: 77px;
  overflow: hidden;
  position: relative;
}
selector .suessco-apps__counter-track {
  transform: translateY(calc(var(--active-index, 0) * -77px));
  transition: transform 0.5s cubic-bezier(0.22, 1, 0.36, 1);
}
selector .suessco-apps__counter-track span {
  display: flex;
  align-items: center;
  justify-content: center;
  width: 100%;
  height: 77px;
  font-size: 56px;
  line-height: 1.2;
  font-weight: 300;
  letter-spacing: -0.02em;
  color: #1476ff;
}
selector .suessco-apps__counter-line {
  position: relative;
  width: 2px;
  height: 120px;
  margin: 24px 0;
  background: #e8e8e8;
  overflow: hidden;
}
selector .suessco-apps__counter-line span {
  position: absolute;
  left: 0;
  top: 0;
  width: 100%;
  height: 100%;
  background: #1476ff;
  transform-origin: top center;
  transform: scaleY(0.08);
  transition: transform 0.45s cubic-bezier(0.22, 1, 0.36, 1);
}
selector .suessco-apps__counter-total {
  font-size: 56px;
  line-height: 1.2;
  font-weight: 300;
  letter-spacing: -0.02em;
  color: rgba(20, 118, 255, 0.29);
}

@media (max-width: 1023px) {
  selector .suessco-apps__stage { display: block; }
  selector .suessco-apps__card {
    position: relative;
    top: auto;
    display: flex;
    flex-direction: column;
    align-items: stretch;
    gap: 24px;
    padding: 8px 8px 24px;
    border-radius: 32px;
    min-height: 0;
    transform: none !important;
    opacity: 1 !important;
    box-shadow: none !important;
  }
  selector .suessco-apps__image-wrap { order: -1; height: 375px; border-radius: 24px; }
  selector .suessco-apps__card-content { max-width: 100%; padding: 16px; }
  selector .suessco-apps__card-title { font-size: 22px; }
  selector .suessco-apps__card-description { font-size: 15px; }
  selector .suessco-apps__heading { font-size: 36px; }
  selector .suessco-apps__counter { display: none; }
}
@media (max-width: 767px) {selector .suessco-apps__image-wrap {  height: 220px;}
}

selector .e-n-accordion-item {
    border-bottom: 1px solid color-mix(in srgb, var(--e-global-color-primary) 30%, transparent);
    border-radius: 0;
    overflow: hidden;
}
selector p {
font-family: Poppins;
font-weight: 400;
font-style: Regular;
font-size: 18px;
line-height: 150%;
letter-spacing: 0%;
}
